import os
import random
import numpy as np
import torch
import soundfile as sf
from torch.utils.data import Dataset

SR = 16000

def read_protocol(path):
    items = []
    with open(path) as f:
        for line in f:
            parts = line.strip().split()
            if len(parts) >= 5:
                uid, label = parts[1], parts[4]
                items.append((uid, 1 if label == 'bonafide' else 0))
    return items

def load_flac(path):
    try:
        wav, sr = sf.read(path, dtype='float32')
        if wav.ndim > 1:
            wav = wav.mean(axis=1)
        if sr != SR:
            import librosa
            wav = librosa.resample(wav, orig_sr=sr, target_sr=SR)
        if len(wav) == 0:
            wav = np.zeros(SR, dtype=np.float32)
        return wav.astype(np.float32)
    except Exception:
        return np.zeros(SR, dtype=np.float32)

# Mu-law encoding/decoding (numpy)
def mulaw_codec(wav, mu=255):
    wav = np.clip(wav, -1, 1)
    enc = np.sign(wav) * np.log1p(mu * np.abs(wav)) / np.log1p(mu)
    # quantize
    enc_q = np.round((enc + 1) / 2 * mu).astype(np.int16)
    enc_dq = enc_q.astype(np.float32) / mu * 2 - 1
    dec = np.sign(enc_dq) * (1.0 / mu) * (np.power(1 + mu, np.abs(enc_dq)) - 1)
    return dec.astype(np.float32)

def alaw_codec(wav, A=87.6):
    wav = np.clip(wav, -1, 1)
    abs_x = np.abs(wav)
    cond = abs_x < 1 / A
    enc = np.where(cond, A * abs_x / (1 + np.log(A)),
                   (1 + np.log(A * abs_x.clip(min=1e-9))) / (1 + np.log(A)))
    enc = np.sign(wav) * enc
    enc_q = np.round(enc * 127).astype(np.int16)
    enc_dq = enc_q.astype(np.float32) / 127.0
    abs_y = np.abs(enc_dq)
    cond2 = abs_y < 1 / (1 + np.log(A))
    dec = np.where(cond2, abs_y * (1 + np.log(A)) / A,
                   np.exp(abs_y * (1 + np.log(A)) - 1) / A)
    dec = np.sign(enc_dq) * dec
    return dec.astype(np.float32)

def downsample_codec(wav, target_sr=8000):
    # simple decimation+interpolation to simulate narrowband
    import librosa
    try:
        x = librosa.resample(wav, orig_sr=SR, target_sr=target_sr)
        x = librosa.resample(x, orig_sr=target_sr, target_sr=SR)
        return x.astype(np.float32)
    except Exception:
        return wav

def bandpass_filter(wav, lo=300, hi=3400):
    from scipy.signal import butter, sosfiltfilt
    try:
        sos = butter(4, [lo, hi], btype='bandpass', fs=SR, output='sos')
        return sosfiltfilt(sos, wav).astype(np.float32)
    except Exception:
        return wav

def add_noise(wav, snr_db):
    sig_p = (wav ** 2).mean() + 1e-9
    noise_p = sig_p / (10 ** (snr_db / 10))
    noise = np.random.randn(len(wav)).astype(np.float32) * np.sqrt(noise_p)
    return wav + noise

def simulated_codec_aug(wav):
    # randomly chain: bandlimit + (mulaw|alaw|downsample) + noise
    choice = random.random()
    if choice < 0.25:
        wav = mulaw_codec(wav)
    elif choice < 0.5:
        wav = alaw_codec(wav)
    elif choice < 0.75:
        wav = downsample_codec(wav, target_sr=random.choice([8000, 8000, 16000]))
        wav = mulaw_codec(wav) if random.random() < 0.5 else wav
    else:
        wav = bandpass_filter(wav, lo=random.choice([100, 300]), hi=random.choice([3400, 4000, 7000]))
    if random.random() < 0.5:
        wav = add_noise(wav, snr_db=random.uniform(15, 35))
    return np.clip(wav, -1, 1).astype(np.float32)

class SpoofDataset(Dataset):
    def __init__(self, items, flac_dir, max_sec=4.0, augment=False, codec_prob=0.7):
        self.items = items
        self.flac_dir = flac_dir
        self.max_len = int(max_sec * SR)
        self.augment = augment
        self.codec_prob = codec_prob

    def __len__(self):
        return len(self.items)

    def __getitem__(self, idx):
        uid, label = self.items[idx]
        wav = load_flac(os.path.join(self.flac_dir, uid + '.flac'))
        if self.augment and random.random() < self.codec_prob:
            wav = simulated_codec_aug(wav)
        if len(wav) >= self.max_len:
            if self.augment:
                start = random.randint(0, len(wav) - self.max_len)
            else:
                start = 0
            wav = wav[start:start + self.max_len]
        if self.augment:
            g = 10 ** (random.uniform(-6, 6) / 20)
            wav = wav * g
            wav = np.clip(wav, -1, 1)
        return torch.from_numpy(np.ascontiguousarray(wav)).float(), label, uid

def collate_fn(batch):
    wavs = [b[0] for b in batch]
    labels = torch.tensor([b[1] for b in batch], dtype=torch.float32)
    uids = [b[2] for b in batch]
    maxlen = max(w.size(0) for w in wavs)
    inputs = torch.zeros(len(wavs), maxlen)
    mask = torch.zeros(len(wavs), maxlen, dtype=torch.long)
    for i, w in enumerate(wavs):
        inputs[i, :w.size(0)] = w
        mask[i, :w.size(0)] = 1
    return inputs, mask, labels, uids
